import { executionsClient, actionExecutionsClient  } from '@dynatrace-sdk/client-automation';
import { queryExecutionClient } from '@dynatrace-sdk/client-query';
import { credentialVaultClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ execution_id, action_execution_id }) {
  // transform tenant url to gen2 for api calls
  let chk_tenant_dev_or_sprit = globalThis.environmentUrl.includes(".dev.") || globalThis.environmentUrl.includes(".sprint.") ;
  if (chk_tenant_dev_or_sprit === true) {
  var tenantURL = globalThis.environmentUrl.replace(".apps", "").replace(".com/", ".com");
  } else {
  var tenantURL = globalThis.environmentUrl.replace(".apps", ".live").replace(".com/", ".com");
  }
  const ex = await execution(execution_id);
   var params = await ex.result('set-variables');
  const rawResponsex = await fetch(''+ tenantURL + '/api/v1/synthetic/monitors?type=BROWSER&enabled=true', {
    method: 'get',
    headers: {
      'Accept': 'application/json',
      'Content-Type': 'application/json',
      'Authorization': 'api-token ' + params.dt_access_token


    },
  });
  //console.log(rawResponse);
  const getid = await rawResponsex.json();
  //console.log(getid.monitors)
  let i = 0;
  while (i < getid.monitors.length) {
      //console.log(getid.monitors[i]);
      if (getid.monitors[i].name == "staging_astroshop") {
      var syn_id = getid.monitors[i].entityId        
      }
      i++;
  }
  console.log("syn_ids: ")
  console.log(syn_id)
  console.log("trigger synthetic test");
  var decodedString = '{ "monitors": [ { "executionCount": 2, "monitorId": "' + syn_id + '", "repeatMode": "SEQUENTIAL" } ] }'

  const rawResponse = await fetch(''+ tenantURL + '/api/v2/synthetic/executions/batch', {
    method: 'POST',
    headers: {
      'Accept': 'application/json',
      'Content-Type': 'application/json',
      'Authorization': 'api-token ' + params.dt_access_token
    },
    body: decodedString
  });
  //console.log(rawResponse);
  const rtriggertest = await rawResponse.json();

  console.log(rtriggertest);
  console.log(rtriggertest.batchId);
  console.log(rtriggertest.executions);


  console.log("Finished Event Found!");
  return { "batchid": rtriggertest.batchId };
}

