      'Content-Type': 'application/json',
      'Authorization': 'api-token ' + params.dt_access_token
    },
  });

  const rtestresults= await rawResponsex.json();
  console.log(rtestresults)

  if(rtestresults.executedCount == 0){ // Sometimes there is a Synth test running at the same time. Fixed by checking if _ANY_ are done.
        console.log("Restarting trying again in 30 seconds");
        throw new Error("No Finished Event yet!");
  } 
// get execution result


  console.log("Finished Event Found!");
  return { "result": rtestresults };
}
